// --- 1. SMART PHISHING DETECTOR ---
function analyzeLink() {
    const input = document.getElementById('urlInput').value.toLowerCase().trim();
    const resultPanel = document.getElementById('urlResult');
    const scanBtn = document.getElementById('scanBtn');
    const loader = document.getElementById('scanLoader');

    if (input === "") return alert("Please paste a link first!");

    // Extract domain safely without using risky Regex
    let domain = input;
    if (domain.indexOf("://") > -1) {
        domain = domain.split('/');
    } else {
        domain = domain.split('/');
    }

    resultPanel.classList.add('hidden');
    loader.classList.remove('hidden');
    scanBtn.disabled = true;
    scanBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> SCANNING...';

    setTimeout(() => {
        loader.classList.add('hidden');
        scanBtn.disabled = false;
        scanBtn.innerHTML = '<i class="fas fa-radar"></i> SCAN NOW';

        document.getElementById('detectedUrl').innerText = domain;
        resultPanel.classList.remove('hidden');
        resultPanel.className = 'result-panel'; 

        if (input.startsWith('http://')) {
            setResult('danger', '⚠️ UNSAFE PROTOCOL', 'This site uses HTTP (Not Encrypted). Data can be intercepted.');
            return;
        }

        let isSafe = false;
        for (let official of officialSites.values()) {
            if (domain.endsWith(official)) {
                isSafe = true;
                break;
            }
        }

        if (isSafe) {
            setResult('safe', '✅ VERIFIED LEGITIMATE', 'This is a verified official domain.');
            return;
        }

        let phishingDetected = false;
        let targetedBrand = '';
        let cleanDomain = domain.split('.').join('').split('-').join(''); 

        for (let of officialSites.entries()) {
            if (cleanDomain.includes(brand) && !domain.endsWith(official)) {
                phishingDetected = true;
                targetedBrand = brand.toUpperCase();
                break;
            }
        }

        if (phishingDetected) {
            setResult('danger', "🚫 PHISHING (" + targetedBrand + ")", "This link mimics " + targetedBrand + " but the domain is fake.");
        } else {
            setResult('danger', '⚠️ SUSPICIOUS', 'Domain not in safety database. Proceed with caution.');
        }

    }, 1500); 
}

function setResult(type, title, text) {
    const panel = document.getElementById('urlResult');
    document.getElementById('resultHeader').innerHTML = title;
    document.getElementById('resultDesc').innerText = text;
    panel.className = "result-panel " + type;
}

// --- Helper Functions to check Characters without Regex ---
function hasUpper(str) { return Array.from(str).some(c => c >= 'A' && c <= 'Z'); }
function hasLower(str) { return Array.from(str).some(c => c >= 'a' && c <= 'z'); }
function hasNumber(str) { return Array.from(str).some(c => c >= '0' && c <= '9'); }
function hasSymbol(str) { 
    return Array.from(str).some(c => !(c >= 'a' && c <= 'z') && !(c >= 'A' && c <= 'Z') && !(c >= '0' && c <= '9')); 
}

// --- 2. PASSWORD ANALYTICS ---
function checkStrength() {
    const pass = document.getElementById('passInput').value;
    const bar = document.getElementById('strengthBar');
    const text = document.getElementById('strengthText');
    const crack = document.getElementById('crackTime');
    const feedbackList = document.getElementById('passFeedback');

    let score = 0;
    let issues = new Array();

    if (pass.length < 8) issues.push("Too short (Minimum 8 chars)");
    else score += 20;

    if (!hasUpper(pass)) issues.push("Add an Uppercase letter (A-Z)");
    else score += 20;

    if (!hasNumber(pass)) issues.push("Add a Number (0-9)");
    else score += 20;

    if (!hasSymbol(pass)) issues.push("Add a Symbol (!@#$)");
    else score += 20;

    const commonPatterns = new Array("password", "1234", "admin", "qwerty", "user");
    let lowerPass = pass.toLowerCase();

    for (let i = 0; i < commonPatterns.length; i++) {
        if (lowerPass.includes(commonPatterns)) {
            score -= 30;
            issues.push("Contains common dictionary word (Avoid 'password', '123')");
            break;
        }
    }

    if (pass.length > 12) score += 20;

    if (score < 0) score = 0;
    if (score > 100) score = 100;

    let color = '#ff2a2a'; let label = 'Weak'; let time = 'Seconds';
    if (score > 40) { color = '#ffae00'; label = 'Medium'; time = '3 Days'; }
    if (score > 60) { color = '#eaff00'; label = 'Good'; time = '5 Months'; }
    if (score > 80) { color = '#00ff88'; label = 'Strong'; time = 'Centuries'; }

    bar.style.width = score + '%';
    bar.style.backgroundColor = color;
    text.innerText = "Strength: " + label;
    crack.innerText = "Crack Time: " + (pass.length === 0 ? "--" : time);

    feedbackList.innerHTML = "";
    if (issues.length > 0 && pass.length > 0) {
        feedbackList.classList.add('active');
        for (let i = 0; i < issues.length; i++) {
            const li = document.createElement('li');
            li.innerText = issues;
            feedbackList.appendChild(li);
        }
    } else {
        feedbackList.classList.remove('active');
    }
}

function hardenPassword() {
    const pass = document.getElementById('passInput').value;
    if (pass.length === 0) return alert("Please enter a password first.");

    const subMap = new Map();
    subMap.set('a', '@'); subMap.set('s', '$'); subMap.set('i', '!'); 
    subMap.set('o', '0'); subMap.set('e', '3'); subMap.set('l', '1');

    let newPass = "";
    for (let i = 0; i < pass.length; i++) {
        let c = pass.charAt(i);
        let lower = c.toLowerCase();
        if (subMap.has(lower)) {
            newPass += subMap.get(lower);
        } else {
            newPass += c;
        }
    }

    // Capitalize the first normal letter we find so it has an Uppercase letter
    let chars = newPass.split('');
    for (let i = 0; i < chars.length; i++) {
        if (chars >= 'a' && chars <= 'z') {
            chars = chars.toUpperCase();
            break;
        }
    }
    newPass = chars.join('');

    // We MUST ensure the length is > 12 to get the "Strong" rating
    // We append a random 4 digit number and 'S#' (e.g., 7878S#)
    let randomNum = Math.floor(Math.random() * 9000) + 1000;
    newPass = newPass + randomNum + "S#";

    document.getElementById('hardenedDisplay').classList.remove('hidden');
    document.getElementById('newPass').innerText = newPass;

    const copyIcon = document.querySelector('#copyBtn i');
    if (copyIcon) copyIcon.className = 'fas fa-copy';

    // Auto-update the strength meter to show how strong the new password is!
    document.getElementById('passInput').value = newPass;
    checkStrength();
}

function copyPassword() {
    const passToCopy = document.getElementById('newPass').innerText;
    if (!passToCopy) return;

    navigator.clipboard.writeText(passToCopy).then(() => {
        const copyIcon = document.querySelector('#copyBtn i');
        if (copyIcon) copyIcon.className = 'fas fa-check';
        setTimeout(() => { if (copyIcon) copyIcon.className = 'fas fa-copy'; }, 2000);
    }).catch(err => alert("Failed to copy password."));
}

// --- 3. PERMISSIONS & 4. DIGITAL FOOTPRINT ---
document.addEventListener('DOMContentLoaded', () => {
    updatePermStatus('camera', 'camStatus');
    updatePermStatus('microphone', 'micStatus');
    loadFootprint(); 
});

async function updatePermStatus(name, id) {
    try {
        const result = await navigator.permissions.query({ name: name });
        const el = document.getElementById(id);
        el.innerText = result.state.toUpperCase();
        el.style.color = result.state === 'granted' ? '#00ff88' : '#b0b0c0';
        result.onchange = () => updatePermStatus(name, id);
    } catch (e) {}
}

async function testCamera() {
    try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: true });
        const video = document.getElementById('videoFeed');
        document.getElementById('camContainer').classList.remove('hidden');
        video.srcObject = stream;
        updatePermStatus('camera', 'camStatus');
    } catch (err) { alert("ACCESS DENIED: Camera blocked."); }
}

async function testMic() {
    try {
        await navigator.mediaDevices.getUserMedia({ audio: true });
        document.getElementById('micContainer').classList.remove('hidden');
        updatePermStatus('microphone', 'micStatus');
    } catch (err) { alert("ACCESS DENIED: Microphone blocked."); }
}

function stopMedia() { location.reload(); }

// --- DIGITAL FOOTPRINT (Exact Model Logic Included) ---
async function loadFootprint() {
    let osInfo = "Unknown OS";
    const ua = navigator.userAgent;

    try {
        // High Entropy API fetches exact model (e.g. chp2723)
        if (navigator.userAgentData && navigator.userAgentData.getHighEntropyValues) {
            const hints = await navigator.userAgentData.getHighEntropyValues(new Array('platform', 'platformVersion', 'model'));
            if (hints.platform === "Windows") {
                const majorVersion = parseInt(hints.platformVersion.split('.'));
                osInfo = majorVersion >= 13 ? "Windows 11 PC" : "Windows 10 PC";
            } else if (hints.platform === "Android") {
                osInfo = hints.model ? "Android (" + hints.model + ")" : "Android Device";
            } else {
                osInfo = hints.platform + (hints.model ? " " + hints.model : "");
            }
        } else {
            // String fallback method for browsers that don't support the API
            if (ua.includes("Win")) osInfo = "Windows PC";
            else if (ua.includes("Mac")) osInfo = "Mac OS";
            else if (ua.includes("iPhone")) osInfo = "iPhone";
            else if (ua.includes("Android")) {
                let parts = ua.split("Android");
                if (parts.length > 1) {
                    let sub = parts.split(";");
                    if (sub.length > 1) {
                        let model = sub.split(")").trim();
                        osInfo = "Android (" + model + ")";
                    }
                } else {
                    osInfo = "Android Device";
                }
            } else {
                osInfo = navigator.platform; 
            }
        }
    } catch (e) {
        osInfo = navigator.platform || "Unknown";
    }
    document.getElementById('osVal').innerText = osInfo;
    document.getElementById('browserVal').innerText = navigator.vendor || "Browser";

    try {
        const bat = await navigator.getBattery();
        document.getElementById('batteryVal').innerText = Math.round(bat.level * 100) + '%';
    } catch(e) {}

    try {
        const req = await fetch('https://ipapi.co/json/');
        const data = await req.json();
        document.getElementById('ipAddress').innerText = data.ip;
        document.getElementById('location').innerText = data.city + ", " + data.country_name;
        document.getElementById('latlong').innerText = data.latitude + ", " + data.longitude + " (IP Approx)";
    } catch (e) {
        document.getElementById('ipAddress').innerText = "AdBlocker / Network Error";
    }

    if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
            (position) => {
                const lat = position.coords.latitude.toFixed(5);
                const lon = position.coords.longitude.toFixed(5);
                document.getElementById('latlong').innerText = lat + ", " + lon + " (GPS Verified)";
                document.getElementById('latlong').style.color = '#00ff88';
            },
            (error) => { /* Silently ignore */ }
        );
    }
}

